#include <stdio.h>
#include <stdlib.h>

// Structure for a graph node
typedef struct Node {
    int data;
    struct Node* next;
} Node;

// Function to create a new node
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->data = data;
    newNode->next = NULL;
    return newNode;
}

// Function to add an edge to the graph
void addEdge(Node** adj, int src, int dest, int numCourses) {
    Node* newNode = createNode(dest);
    if (adj[src] == NULL) {
        adj[src] = newNode;
    } else {
        Node* lastNode = adj[src];
        while (lastNode->next) {
            lastNode = lastNode->next;
        }
        lastNode->next = newNode;
    }
}

// Function to perform topological sorting using BFS
int* findOrder(int numCourses, int** prerequisites, int prerequisitesSize, int* returnSize) {
    Node** adj = (Node**) malloc(numCourses * sizeof(Node*));
    int* inDegree = (int*) malloc(numCourses * sizeof(int));
    int* order = (int*) malloc(numCourses * sizeof(int));
    *returnSize = 0;

    // Initialize adjacency list and in-degree array
    for (int i = 0; i < numCourses; i++) {
        adj[i] = NULL;
        inDegree[i] = 0;
    }

    // Build adjacency list and in-degree array
    for (int i = 0; i < prerequisitesSize; i++) {
        addEdge(adj, prerequisites[i][1], prerequisites[i][0], numCourses);
        inDegree[prerequisites[i][0]]++;
    }

    // Initialize queue with nodes having an in-degree of 0
    int queue[numCourses], front = 0, rear = -1;
    for (int i = 0; i < numCourses; i++) {
        if (inDegree[i] == 0) {
            queue[++rear] = i;
        }
    }

    // Process queue
    while (front <= rear) {
        int node = queue[front++];
        order[(*returnSize)++] = node;

        Node* temp = adj[node];
        while (temp) {
            inDegree[temp->data]--;
            if (inDegree[temp->data] == 0) {
                queue[++rear] = temp->data;
            }
            temp = temp->next;
        }
    }

    // Check if all nodes are processed
    if (*returnSize != numCourses) {
        *returnSize = 0;
    }

    return order;
}

